interface IBigNumberContent {
  number: number | string;  // The main numeric value to display (string for time values like "21:59")
  subheading: string;       // Descriptive text below the number
  fontColor: string;        // Color for number, text, and subheading text
  link: IBigNumberLink;     // Link configuration object
  text?: string;            // Optional text displayed alongside the number (e.g., "hrs", "AM")
  textSize?: number;        // Optional font size in rem for the text element
}`,IBigNumberLink:`
interface IBigNumberLink {
  url: string;         // The destination URL
  text: string;        // Link text to display
  isExternal: boolean; // Whether link opens in new tab/window
}`},usage:{basic:`
